if (HipsMgr.getFlagShow()) {
    core.debug("HiPS surveys are visible");
} else {
    HipsMgr.setFlagShow(true);
}

// Enable HiPS surveys
HipsMgr.setFlagShow(true);

// Disable HiPS surveys
HipsMgr.setFlagShow(false);

var survey = HipsMgr.getSurveyByUrl("https://alasky.cds.unistra.fr/DSS/DSS2M");
if (survey) {
    core.debug("Survey found: " + survey.getShortName());
    survey.setVisible(true);
}

var state = HipsMgr.getState();
if (state === 0) {
    core.debug("HiPS not loaded yet");
} else if (state === 1) {
    core.debug("HiPS loading...");
} else if (state === 2) {
    core.debug("HiPS loaded and ready");
}

var state = core.getStelProperty('HipsMgr.state');
if (state === 2) {
    core.debug("HiPS surveys are ready");
}

if (HipsMgr.isLoaded()) {
    core.debug("HiPS surveys are ready");
    HipsMgr.setFlagShow(true);
}

var isLoaded = core.getStelProperty('HipsMgr.loaded');
if (isLoaded) {
    core.debug("HiPS surveys are ready to use");
}
